import React, { useState, useEffect } from "react";
import { getCurrentUser, hasAccess } from "../utils/auth";


const Placement = () => {
  const user = getCurrentUser();

  const [placements, setPlacements] = useState([]);
  const [newPlacement, setNewPlacement] = useState({ role: "", company: "", package: "" });

  const isAdmin = user?.role === "Admin";
  const isHR = user?.role === "HR";
  const isStudent = user?.role === "Student";

  const fetchPlacements = () => {
    const stored = JSON.parse(localStorage.getItem("placements")) || [];
    setPlacements(stored);
  };

  useEffect(() => {
    fetchPlacements();
  }, []);

  const handleAdd = () => {
    const updated = [...placements, newPlacement];
    localStorage.setItem("placements", JSON.stringify(updated));
    setNewPlacement({ role: "", company: "", package: "" });
    fetchPlacements();
  };

  const handleDelete = (index) => {
    const updated = placements.filter((_, i) => i !== index);
    localStorage.setItem("placements", JSON.stringify(updated));
    fetchPlacements();
  };

  const handleApply = (index) => {
    alert(`Applied to: ${placements[index].role}`);
  };

  return (
    <div className="p-6">
      <h2 className="text-3xl font-bold mb-4">Placements</h2>

      {(isAdmin || isHR) && (
        <div className="mb-6 space-y-2">
          <input
            className="border px-2 py-1 w-full"
            placeholder="Role"
            value={newPlacement.role}
            onChange={(e) => setNewPlacement({ ...newPlacement, role: e.target.value })}
          />
          <input
            className="border px-2 py-1 w-full"
            placeholder="Company"
            value={newPlacement.company}
            onChange={(e) => setNewPlacement({ ...newPlacement, company: e.target.value })}
          />
          <input
            className="border px-2 py-1 w-full"
            placeholder="Package"
            value={newPlacement.package}
            onChange={(e) => setNewPlacement({ ...newPlacement, package: e.target.value })}
          />
          <button className="bg-green-600 text-white px-4 py-1 rounded" onClick={handleAdd}>
            Add Placement
          </button>
        </div>
      )}

      <div className="space-y-4">
        {placements.map((place, index) => (
          <div key={index} className="border p-4 rounded shadow-sm bg-gray-100">
            <h3 className="text-xl font-semibold">{place.role}</h3>
            <p>{place.company}</p>
            <p>Package: {place.package}</p>

            {isStudent && (
              <button
                className="mt-2 bg-blue-500 text-white px-3 py-1 rounded"
                onClick={() => handleApply(index)}
              >
                Apply
              </button>
            )}

            {isAdmin && (
              <button
                className="ml-2 mt-2 bg-red-500 text-white px-3 py-1 rounded"
                onClick={() => handleDelete(index)}
              >
                Delete
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default Placement;
